const lokiResponse = $input.first().json;
const alertData = $('Is Adult Site Alert?').first().json;

const clientIPs = new Set();
const domains = new Set();

if (lokiResponse.data && lokiResponse.data.result) {
  for (const stream of lokiResponse.data.result) {
    if (stream.stream && stream.stream.client) {
      clientIPs.add(stream.stream.client);
    }
    if (stream.values) {
      for (const [ts, line] of stream.values) {
        const ipMatch = line.match(/from\s+(\d+\.\d+\.\d+\.\d+)/);
        if (ipMatch) clientIPs.add(ipMatch[1]);
        const domainMatch = line.match(/query\[[A-Z]+\]\s+([^\s]+)/);
        if (domainMatch) domains.add(domainMatch[1]);
      }
    }
  }
}

return {
  json: {
    ...alertData,
    clientIPs: Array.from(clientIPs),
    domains: Array.from(domains),
    logCount: lokiResponse.data?.result?.length || 0
  }
};

const alert = $input.item.json;
const status = alert.status || 'unknown';
const severity = (alert.labels && alert.labels.severity) || 'warning';
const alertName = (alert.labels && alert.labels.alertname) || 'Unknown Alert';
const clientIPs = alert.clientIPs || [];
const domains = alert.domains || [];
let statusEmoji = '🚨';
if (status === 'resolved') statusEmoji = '✅';
const summary = (alert.annotations && (alert.annotations.summary || alert.annotations.description)) || 'Adult site query detected';
let timestamp;
if (alert.startsAt) {
  timestamp = new Date(alert.startsAt).toLocaleString('en-US', { timeZone: 'America/New_York' });
} else {
  timestamp = new Date().toLocaleString('en-US', { timeZone: 'America/New_York' });
}
let message = statusEmoji + ' *' + status.toUpperCase() + '* - ' + alertName + '\n\n';
message += '*Summary:* ' + summary + '\n';
message += '*Time:* ' + timestamp + '\n\n';
if (clientIPs.length > 0) {
  message += '*Client IP(s):*\n';
  for (const ip of clientIPs) message += '  - `' + ip + '`\n';
} else {
  message += '*Client IP(s):* Unable to retrieve\n';
}
if (domains.length > 0) {
  message += '\n*Domain(s) Queried:*\n';
  for (const domain of domains) message += '  - `' + domain + '`\n';
}
const dashboardUrl = alert.generatorURL || alert.dashboardURL || '';
if (dashboardUrl) message += '\n[View in Grafana](' + dashboardUrl + ')';
return { json: { alertName, status, severity, message, clientIPs, domains, dashboardUrl } };

const alert = $input.item.json;
const status = alert.status || 'unknown';
const severity = (alert.labels && alert.labels.severity) || 'info';
const alertName = (alert.labels && alert.labels.alertname) || 'Unknown Alert';
let statusEmoji = '🟡';
if (status === 'firing') {
  statusEmoji = severity === 'critical' ? '🔴' : '🟡';
} else if (status === 'resolved') {
  statusEmoji = '🟢';
}
const summary = (alert.annotations && (alert.annotations.summary || alert.annotations.description)) || 'No description provided';
let valuesStr = 'N/A';
if (alert.valueString) {
  valuesStr = alert.valueString;
} else if (alert.values && typeof alert.values === 'object') {
  const entries = Object.entries(alert.values);
  if (entries.length > 0) valuesStr = entries.map(e => e[0] + ': ' + e[1]).join(', ');
}
let timestamp;
if (alert.startsAt) {
  timestamp = new Date(alert.startsAt).toLocaleString('en-US', { timeZone: 'America/New_York' });
} else {
  timestamp = new Date().toLocaleString('en-US', { timeZone: 'America/New_York' });
}
const dashboardUrl = alert.generatorURL || alert.dashboardURL || '';
let message = statusEmoji + ' *' + status.toUpperCase() + '* - ' + alertName + '\n\n';
message += '*Severity:* ' + severity + '\n';
message += '*Summary:* ' + summary + '\n';
message += '*Values:* ' + valuesStr + '\n';
message += '*Time:* ' + timestamp;
if (dashboardUrl) message += '\n\n[View in Grafana](' + dashboardUrl + ')';
return { json: { alertName, status, severity, message, dashboardUrl } };
